const[whereExtras,setWhereExtras]=useState([]);const[whereBuilderOpen,setWhereBuilderOpen]=useState(false);// --- STATUS EXTRAS (adicionales al STATUS=2 fijo) ---
const[statusExtrasRaw,setStatusExtrasRaw]=useState('');// string "3,4,5"
