const[activeExtraCols,setActiveExtraCols]=useState(new Set());// --- CONSULTA ---
const[isConsultando,setIsConsultando]=useState(false);const[panelMessage,setPanelMessage]=useState({type:'',text:''});// --- GRUPOS / SELECCIÓN ---
